extension WKInterfaceDevice {
    class func currentResolution() -> WatchResolution {
        let watch38mmRect = CGRect(x: 0, y: 0, width: 136, height: 170)
        let watch40mmRect = CGRect(x: 0, y: 0, width: 162, height: 197)
        let watch42mmRect = CGRect(x: 0, y: 0, width: 156, height: 195)
        let watch44mmRect = CGRect(x: 0, y: 0, width: 184, height: 224)

        let currentBounds = WKInterfaceDevice.current().screenBounds

        switch currentBounds {
        case watch38mmRect:
            return .Watch38mm
        case watch40mmRect:
            return .Watch40mm
        case watch42mmRect:
            return .Watch42mm
        case watch44mmRect:
            return .Watch44mm
        default:
            return .Unknown
        }
    }
}

public struct AnyComparable: Comparable {
  public let base: Any
  let isEqual: (Any) -> Bool
  let compare: (Any) -> Bool

  public init(
    base: Any,
    isEqual: @escaping (Any) -> Bool,
    compare: @escaping (Any) -> Bool
  ) {
    self.base = base
    self.isEqual = isEqual
    self.compare = compare
  }

  public init<C: Equatable>(_ base: C, compare: @escaping (C, C) -> Bool) {
    self.base = base
    self.isEqual = { other in
      (other as? C) == base
    }
    self.compare = { other in
      (other as? C).map { compare(base, $0) } ?? false
    }
  }

  public init<C: Comparable>(_ base: C) {
    self.base = base
    self.isEqual = { other in
      (other as? C) == base
    }
    self.compare = { other in
      (other as? C).map { base < $0 } ?? false
    }
  }

  public static func == (lhs: Self, rhs: Self) -> Bool {
    lhs.isEqual(rhs.base)
  }

  public static func < (lhs: Self, rhs: Self) -> Bool {
    lhs.compare(rhs.base)
  }

  public var reversed: Self {
    .init(base: self.base, isEqual: self.isEqual, compare: { !self.compare($0) })
  }
}

